def asset_data_uri(rel_path):
    return cached_asset_data_uri(os.path.join(os.getcwd(), rel_path))

def first_existing_asset(paths):
    for rel_path in paths:
        uri = asset_data_uri(rel_path)
        if uri:
            return uri
    return ""

