def infer_exam(item):
    exam = item.get("exam")
    if exam:
        return exam
    cat = str(item.get("category", "")).strip()
    if "لفظ" in cat:
        return "قدرات لفظي"
    if "تحصيلي" in cat:
        return "تحصيلي"
    return "قدرات كمي"

questions_data = load_json(os.path.join("data", "questions.json"), [])
if not isinstance(questions_data, list):
    questions_data = []

for item in questions_data:
    item["exam"] = infer_exam(item)
    item.setdefault("time_per_question_sec", 60)

image_map = {}
def normalize_image_key(path):
    return str(path or "").replace("\\", "/").lstrip("./").strip()

def find_image_file(rel_path):
    rel_key = normalize_image_key(rel_path)
    base_name = os.path.basename(rel_key)

    candidates = [
        rel_path,
        rel_key,
        os.path.join(os.getcwd(), rel_key),
        os.path.join(os.getcwd(), rel_path),
        os.path.join(os.getcwd(), "assets", "images", base_name),
        os.path.join("assets", "images", base_name),
    ]

    for candidate in candidates:
        if candidate and os.path.exists(candidate):
            return candidate

    # fallback: لو حطيت الصورة داخل مجلد images بأي مكان، يبحث عنها بالاسم
    images_root = os.path.join(os.getcwd(), "assets", "images")
    if base_name and os.path.isdir(images_root):
        for root, _, files in os.walk(images_root):
            if base_name in files:
                return os.path.join(root, base_name)

    return ""

for item in questions_data:
    rel_path = item.get("image")
    if not rel_path:
        continue

    rel_key = normalize_image_key(rel_path)
    found = find_image_file(rel_path)

    if found:
        mime = mimetypes.guess_type(found)[0] or "image/png"
        with open(found, "rb") as imgf:
            b64 = base64.b64encode(imgf.read()).decode("utf-8")
        uri = f"data:{mime};base64,{b64}"

        # يدعم المسار الكامل + اسم الصورة فقط
        image_map[rel_key] = uri
        image_map[str(rel_path)] = uri
        image_map[os.path.basename(rel_key)] = uri
        image_map["assets/images/" + os.path.basename(rel_key)] = uri

questions_json = compact_json(questions_data)
image_map_json = compact_json(image_map)

