_existing_summary_keys = {(s.get("exam"), s.get("subject"), s.get("unit")) for s in summaries_data if isinstance(s, dict)}
for _s in qiyas_summaries_seed:
    _key = (_s.get("exam"), _s.get("subject"), _s.get("unit"))
